=/**
 * EXTRATOR + NORMALIZADOR UNIVERSAL
 * - Extrai transações do markdown/OCR
 * - Normaliza para o formato final do banco de dados
 */

// ========================================
// 1. DADOS DA CONTA
// ========================================

let accountId = "";
let bankName = "";

try {
  const webhook = $('Recebe link do Supabase Storage2').first().json;
  const webData = webhook.body || webhook;

  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
} catch (e) {
  bankName = "Banco";
}

// ========================================
// 2. CONFIGURAÇÃO DE MESES
// ========================================

const meses = {
  "janeiro": "01",
  "fevereiro": "02",
  "março": "03",
  "abril": "04",
  "maio": "05",
  "junho": "06",
  "julho": "07",
  "agosto": "08",
  "setembro": "09",
  "outubro": "10",
  "novembro": "11",
  "dezembro": "12"
};

// ========================================
// 3. EXTRAÇÃO DAS TRANSAÇÕES
// ========================================

const inputData = $input.all();
const listaBruta = [];

for (const item of inputData) {

  // Tenta pegar texto de qualquer campo possível
  const textoBruto =
    item.json.markdown ||
    item.json.extractedText ||
    item.json.text ||
    "";

  // Caso já venha estruturado
  if (Array.isArray(item.json.output)) {
    listaBruta.push(...item.json.output);
    continue;
  }

  const linhas = textoBruto.split('\n');

  let dataVigente = null;

  for (let linha of linhas) {

    linha = linha.trim();

    if (!linha) continue;

    // ========================================
    // IGNORA LINHAS IRRELEVANTES
    // ========================================

    if (
      linha.includes("SAC:") ||
      linha.includes("Ouvidoria:") ||
      linha.includes("Deficiência") ||
      linha.includes("Fale com a gente")
    ) {
      continue;
    }

    // ========================================
    // DETECTA CABEÇALHO DE DATA
    // Ex: "16 de Janeiro de 2026"
    // ========================================

    const regexData = /(\d{1,2})\s+de\s+([a-zA-Zçãó]+)\s+de\s+(\d{4})/i;

    const matchData = linha.match(regexData);

    if (matchData) {

      const dia = matchData[1].padStart(2, '0');
      const mesTexto = matchData[2].toLowerCase();
      const ano = matchData[3];

      const mes = meses[mesTexto] || "01";

      dataVigente = `${dia}/${mes}/${ano}`;

      continue;
    }

    // ========================================
    // CAPTURA LINHAS DE TABELA MARKDOWN
    // ========================================

    if (
      linha.startsWith('|') &&
      !linha.includes('---') &&
      !linha.includes('Saldo total') &&
      !linha.includes('Valor |')
    ) {

      const colunas = linha
        .split('|')
        .map(c => c.trim())
        .filter(c => c !== "");

      if (colunas.length >= 2) {

        const descricaoBruta = colunas[0];
        const valorBruto = colunas[1];

        // ========================================
        // NORMALIZA VALOR
        // ========================================

        let valorTexto = valorBruto
          .replace(/[R$\s\.]/g, '')
          .replace(',', '.');

        let valor = parseFloat(valorTexto) || 0;

        const sinal = valor < 0 ? '-' : '+';

        valor = Math.abs(valor);

        // ========================================
        // SALVA TRANSAÇÃO
        // ========================================

        if (dataVigente && descricaoBruta) {

          listaBruta.push({
            d: dataVigente,
            t: descricaoBruta.replace(/"/g, '').trim(),
            v: valor,
            s: sinal
          });

        }
      }
    }
  }
}

// ========================================
// 4. NORMALIZAÇÃO FINAL
// ========================================

const anoAtual = new Date().getFullYear();

const final = listaBruta.map((item, index) => {

  const desc = (item.t || "")
    .toString()
    .toUpperCase()
    .trim();

  let v = item.v !== undefined ? item.v : 0;

  if (typeof v === 'string') {
    v = v
      .replace(/[R$\s]/ig, '')
      .replace(',', '.');
  }

  let valorFinal = parseFloat(v) || 0;

  // ========================================
  // APLICA SINAL
  // ========================================

  if (
    item.s === "-" ||
    item.s === "despesa"
  ) {
    valorFinal = -Math.abs(valorFinal);
  } else {
    valorFinal = Math.abs(valorFinal);
  }

  // ========================================
  // NORMALIZA DATA
  // dd/mm/yyyy -> yyyy-mm-dd
  // ========================================

  let dataF = item.d || "";

  if (dataF.includes('/')) {

    const p = dataF.split('/');

    dataF = `${p[2] || anoAtual}-${p[1].padStart(2, '0')}-${p[0].padStart(2, '0')}T12:00:00`;
  }

  // ========================================
  // DEFINE TIPO
  // ========================================

  const categoriasNeutras = [
    "reembolsos",
    "estorno",
    "pagamento-fatura-cartao",
    "transferencia-mesma-titularidade",
    "despesas-reembolsaveis",
    "reserva-emergencia",
    "projetos-vida",
    "independencia-financeira"
  ];

  const tipo =
    valorFinal < 0
      ? "despesa"
      : categoriasNeutras.includes(item.c)
        ? "neutro"
        : "receita";

  // ========================================
  // RETORNO FINAL
  // ========================================

  return {
    json: {
      account_id: accountId,
      Conta: bankName,

      Data_lancamento: dataF,
      Data_pagamento: dataF,

      Descricao: desc,

      Valor: valorFinal,

      Tipo: tipo,

      Categoria: item.c || "outros-gv",

      id_conciliacao: `${desc}-${valorFinal}-${index}`
    }
  };

});

return final;

=// ========================================
// 1. ENTRADA
// ========================================

const rawText = $input.first().json.extractedText;

if (!rawText) {
  throw new Error("A propriedade 'extractedText' está vazia.");
}

// ========================================
// 2. CONFIG
// ========================================

const currentYear = new Date().getFullYear();

const ignoredTerms = [
  'total dos',
  'lançamentos no',
  'pagamento recebido',
  'saldo anterior',
  'encargos',
  'juros',
  'iof',
  'anuidade',
  'limite disponível'
];

// ========================================
// 3. NORMALIZA TEXTO
// ========================================

// remove espaços duplicados
const normalizedText = rawText
  .replace(/\r/g, '')
  .replace(/\t/g, ' ')
  .replace(/[ ]{2,}/g, ' ');

// ========================================
// 4. REGEX MAIS FLEXÍVEL
// ========================================

// captura:
// | 27/12 | UBER *TRIP | 32,90 |
// | 05/01 | PARC=03/10 MAGAZINE LUIZA | 199,90 |
// | 11/02 | IFOOD\nSAO PAULO BR | 58,22 |

const transactionRegex =
  /\|\s*(\d{2}\/\d{2})\s*\|\s*([\s\S]*?)\s*\|\s*(-?[\d.]+,\d{2})\s*\|/g;

const transactions = [];

let match;

// ========================================
// 5. EXTRAÇÃO
// ========================================

while ((match = transactionRegex.exec(normalizedText)) !== null) {

  const dataOriginal = match[1]?.trim();

  let descricao = match[2]
    ?.replace(/\n/g, ' ')
    ?.replace(/[ ]{2,}/g, ' ')
    ?.trim();

  let valorStr = match[3]?.trim();

  if (!descricao || !valorStr) {
    continue;
  }

  // ========================================
  // FILTRO DE LINHAS INVÁLIDAS
  // ========================================

  const descricaoLower = descricao.toLowerCase();

  const shouldIgnore = ignoredTerms.some(term =>
    descricaoLower.includes(term)
  );

  if (shouldIgnore) {
    continue;
  }

  // evita headers
  if (
    descricaoLower === 'estabelecimento' ||
    descricaoLower === 'valor' ||
    descricaoLower === 'data'
  ) {
    continue;
  }

  // ========================================
  // VALOR
  // ========================================

  valorStr = valorStr
    .replace(/\./g, '')
    .replace(',', '.');

  const valorNumerico = parseFloat(valorStr);

  if (isNaN(valorNumerico)) {
    continue;
  }

  // ========================================
  // DATA
  // ========================================

  const [dia, mes] = dataOriginal.split('/');

  const dataFormatada = `${dia}/${mes}/${currentYear}`;

  // ========================================
  // TIPO
  // ========================================

  const tipo = valorNumerico < 0
    ? 'receita'
    : 'despesa';

  // ========================================
  // RESULTADO
  // ========================================

  transactions.push({
    json: {
      data: dataFormatada,
      descricao,
      valor: Math.abs(valorNumerico),
      tipo
    }
  });
}

// ========================================
// 6. RETORNO
// ========================================

if (transactions.length === 0) {
  return [{
    json: {
      aviso: 'Nenhuma transação encontrada.'
    }
  }];
}

return transactions;

